var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 현실 전초기지, <color=#ffd34c>쉘터 No.72</color>\\n관리국 제4 수색전대 <color=#ffd34c>야크샤</color> 임시 본부","JPN":"管理局現実前哨基地、<color=#ffd34c>シェルターNo.72</color>\\n管理局第4捜索戦隊<color=#ffd34c>ヤクシャー</color>臨時本部","ENG":"Administration's Normalside Frontier Base, <color=#ffd34c>Shelter No. 72</color>\\nAdministration 4th Recon Division <color=#ffd34c>Yaksha</color>'s temporary HQ","TWN":"管理局現世前哨站，<color=#ffd34c>72號庇護所</color>\\n管理局第4偵察戰隊<color=#ffd34c>夜叉</color>臨時總部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……그런 경위로, 현장에서 구조했던 구조자의 기억 소거를 완료하였습니다.","JPN":"……というわけで、現場で救助した救助者の記憶消去を行いました。","ENG":"...And so, we successfully erased the rescuee's memories regarding this incident.","TWN":"……就是這樣，現場救出的相關人員的記憶已經被抹除。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이상, 결과보고를 마치겠습니다.","JPN":"報告は以上です。","ENG":"That concludes my briefing.","TWN":"以上，本次報告到此結束。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"응, 수고했어~","JPN":"うん、お疲れ様～","ENG":"Very well, good work.","TWN":"嗯，辛苦了～"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"관리국 대 침식 작전에 협조해주셔서 감사합니다. 야크샤 부전대장님.","JPN":"管理局の対侵食作戦にご協力いただきありがとうございました、ヤクシャー副戦隊長。","ENG":"Thank you for cooperating in the Administration's anti-Corruption operation, Yaksha Deputy Commander.","TWN":"感謝你們配合管理局的侵蝕作戰。夜叉副戰隊長。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"야크샤의 협조로 민간 피해 없이, 무사히 작전을 성공할 수 있었습니다.","JPN":"ヤクシャーの協力のおかげで民間人の被害なく、無事作戦を終えることができました。","ENG":"We were able to complete the operation without any civilian casualties thanks to your cooperation.","TWN":"多虧了夜叉的配合，作戰順利完成，沒有造成任何民眾傷亡。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"글쎄? 나한테 감사할 필요는 없는 걸?","JPN":"いや、私にお礼を言う必要はないよ。","ENG":"Hmm, I don't think there's any need to thank me.","TWN":"這個嘛？你好像不用謝我？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국 전대라면 어느 곳이든 흔쾌히 작전에 협조했을 거라고 생각해.","JPN":"私たちじゃなくても、管理局の戦隊なら誰でも快く協力していたと思う。","ENG":"I believe any division of the Administration would've willingly cooperated with the operation.","TWN":"我想任何一個管理局戰隊都會願意配合作戰的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그건 그렇지만…….","JPN":"それはそうですが……","ENG":"Yes, of course, but...","TWN":"話雖如此……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"이번 작전에서 야크샤의 <color=#ffd34c>신입 전대원</color>이 큰 활약을 했다고 들었습니다.","JPN":"今回の作戦で、ヤクシャーの<color=#ffd34c>新入戦隊員</color>が大きく貢献したと聞きました。","ENG":"I heard that Yaksha's <color=#ffd34c>rookie</color> played a great role in this operation.","TWN":"聽說在這次作戰中，夜叉的<color=#ffd34c>新隊員</color>表現非常出色。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"<color=#ffd34c>그 사건</color>이후로, 전력이 약화됐다고 들었는데…….","JPN":"<color=#ffd34c>あの事件</color>以来、戦力が弱化したいう話を聞きましたが……","ENG":"I heard that your division had weakened after <color=#ffd34c>that incident</color>...","TWN":"我聽說<color=#ffd34c>那次事件</color>之後，貴戰隊的戰力損失不小。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"야크샤 전대가 순조롭게 회복하고 있는 것 같아서 마음이 놓입니다.","JPN":"ヤクシャー戦隊の戦力が順調に回復している様で、とても安心しました。","ENG":"But seeing your division recovering puts my mind at ease.","TWN":"看到夜叉戰隊恢復得很順利，我就放心了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 걱정해줘서 고맙네.","JPN":"ふふ、心配ありがとう。","ENG":"Fu fuu. Well, thank you for your concern.","TWN":"呵呵，謝謝關心。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그럼, 현실에 주둔하고 계시는 동안 도움이 필요하시다면 불러주십시오.","JPN":"では、現実に駐屯される間何かこちらがお役に立てることがありましたら、お気軽にお声がけください。","ENG":"Then, if you need any help while you're in the Normalside, please don't hesitate to call.","TWN":"那麼，如果你駐守現實世界期間需要幫助，請致電我們。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"언제든 도와드리겠습니다.","JPN":"いつでもお手伝いします。","ENG":"We'll be more than happy to help.","TWN":"我們很樂意隨時為你提供幫助。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 사건이라…….","JPN":"あの事件、ね……","ENG":"That incident...","TWN":"那次事件啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"야크샤 전대원 분들. 다들 진정해 주세요.","JPN":"ヤクシャー戦隊員の皆さん、落ち着いてください。","ENG":"All Yaksha members, please calm down.","TWN":"夜叉戰隊的各位。請大家冷靜一下。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"웃기지 마, 모네카!","JPN":"ふざけるな、モネカ！","ENG":"Don’t be ridiculous, Moneka!","TWN":"別開玩笑了，莫奈卡！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"지금 우리보고 이런 결정을 받아들이라는 거야?","JPN":"こんな決定を受け入れろって言うのか！","ENG":"How could you tell us to accept that decision?","TWN":"你要我們怎麼接受這個決定！？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"진정해 다니엘, 모네카는 그냥 관리국의 의사를 전달하는 것뿐이야.","JPN":"落ち着いて、ダニエル。モネカはただ、管理局の意思を伝えただけよ。","ENG":"Calm down, Daniel. Moneka is just relaying the Administration's decision.","TWN":"冷靜點，丹尼爾，莫奈卡只是在轉達​​管理局的意思。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"모네카한테 화내봤자, 아무 의미 없어.","JPN":"モネカに怒っても意味ないもの。","ENG":"Getting angry at Moneka will change nothing.","TWN":"對莫奈卡發脾氣，沒有任何意義。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"그렇지만 누님!","JPN":"でも姉貴！","ENG":"But...!","TWN":"但是姊姊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"저도 다니엘의 생각에 찬성이에요, 스위프트 부전대장님.","JPN":"私もダニエルと同意見です、スウィフト副戦隊長。","ENG":"I agree with Daniel, Deputy Commander.","TWN":"我也贊成丹尼爾的想法，斯威福特副戰隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"아무리 관리국의 하이브 컨트롤의 결정이라고 해도.","JPN":"いくら管理局のハイブコントロールの決定とはいえ……","ENG":"Even if it's the Administration Hive Control's decision.","TWN":"哪怕是由管理局巢穴控制系統做出的決定。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"전대 내부의 자율권을 침해하는 건 있을 수 없는 일이에요.","JPN":"戦隊の自律権を侵害するのはありえないことです。","ENG":"I don't think they're allowed to infringe on the autonomy of our division.","TWN":"也不能侵犯戰隊內部的自主權。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"<color=#ffd34c>라이오넬</color> 전대장님의 부재로 부대를 재편성해야 한다는 건 동의합니다.","JPN":"<color=#ffd34c>ライオネル</color>戦隊長の不在によって、部隊の編成を見直すという意見には同意します。","ENG":"I agree that we should restructure the division since Commander <color=#ffd34c>Lionel</color> is absent.","TWN":"如今<color=#ffd34c>萊諾</color>戰隊長不在，我同意部隊需要進行重組。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"하지만 새로운 전대장이 선발되어야 한다면…….","JPN":"しかし、新しい戦隊長を選抜するなら……","ENG":"But if a new Commander is to be appointed...","TWN":"但如果必須選出一個新的戰隊長……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"그건, 그분의 유지를 이은 당신이어야만 해요. 주디 스위프트 부전대장님.","JPN":"それはあの方の意思を受け継いだ人、あなたじゃないと駄目です。ジュディ・スウィフト副戦隊長。","ENG":"I think that person should be you, Deputy Commander Judy Swift.","TWN":"那個人，只能是繼承了他意志的你。茱蒂·斯威福特副戰隊長。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"카운터 각성조차 하지 않은 미래의 <color=#ffd34c>신참</color>이 아니라.","JPN":"カウンター覚醒すらしていない、未来の<color=#ffd34c>新入り</color>じゃなくて。","ENG":"Not a <color=#ffd34c>rookie</color> from the future who hasn't even awakened as a Counter.","TWN":"而不是一個還沒有覺醒的未來的<color=#ffd34c>新人</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"맞습니다!","JPN":"そうです！","ENG":"She's right!","TWN":"沒錯！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"그동안 라이오넬 전대장님과 함께 야크샤를 이끌어 왔던 건, 누님이지 않습니까!","JPN":"今までライオネル戦隊長と一緒にヤクシャーを引っ張て来たのは姉貴じゃないですか！","ENG":"You're the one who led Yaksha alongside Commander Lionel!","TWN":"一直以來，和萊諾戰隊長一起帶領夜叉的人，是姊姊你啊！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_A","text":{"KOREA":"어디서 굴러먹었는지도 모르는 도둑고양이가 아니라……!","JPN":"どこの馬の骨かもわからない泥棒猫なんかじゃなくて……！","ENG":"Not this thieving cat that we know nothing about–!","TWN":"不是那個不知道從哪冒出來的野貓……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 말이야.","JPN":"でもね。","ENG":"However.","TWN":"但是。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"테라브레인이 연산한 인과 예측은 그동안 한 번도 틀린 적이 없었어.","JPN":"テラブレインが演算した因果予測が外れたことなど、今まで一度もなかったよ。","ENG":"Terrabrain's causality calculations and predictions have never been wrong.","TWN":"特拉大腦對於因果的運算預測從未出錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"우리 의사를 관리국에 전달하면, 관리국은 그걸 변수 삼아, 차선책을 제시해 줄지도 모르지.","JPN":"私たちの意思を管理局に伝えたら、それを考慮した代案を提案してもらえるかもしれない。","ENG":"And if we deliver our opinion, the Administration will take it as a variable and perhaps provide us with the next best solution.","TWN":"如果將我們的想法傳達給管理局，管理局或許會將其作為變數，提出第二方案。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 그건 어디까지나 차선책이야.","JPN":"でも、それはあくまで第2案にすぎないの。","ENG":"But that's all that it is. A second-best solution.","TWN":"……但這畢竟是第二方案。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 그 차선책마저 우리의 마음에 들 거라는 보장은 없어.","JPN":"それに、その第2案が私たち皆が納得できるものとは限らない。","ENG":"Furthermore, there is no guarantee that it'll be to our liking.","TWN":"而且，也不能保證第二方案就會讓我們滿意。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEMBER_YAKSHA_NPC_B","text":{"KOREA":"그렇지만…….","JPN":"ですが……","ENG":"But still...","TWN":"可是……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 정말이지.","JPN":"ふふ、まったく。","ENG":"Fu fuu, oh, you.","TWN":"呵呵，真是的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"귀랑 꼬리 때문에 다들 무슨 생각하는지 훤히 보인다니까?","JPN":"耳と尻尾のせいで、皆なにを考えてるのかバレバレじゃない。","ENG":"I can tell what everyone is thinking from all your ears and tails.","TWN":"因為耳朵和尾巴，大家的想法我都看得一清二楚。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"불만이 있다는 건 알겠지만, 다들 걱정할 필요는 없어.","JPN":"不満に思う気持ちはわかるけど、そんなに心配する必要はないよ。","ENG":"I understand your frustration, but there's no need to worry.","TWN":"我知道大家有所抱怨，但沒必要擔心。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 내가 선택되지 않았다면, 다 그럴만한 이유가 있을 거야.","JPN":"私が戦隊長に選ばれなかったら、それなりの理由があるはず。","ENG":"If I wasn't chosen as the next Commander, I'm sure there's a good reason.","TWN":"如果我沒有被選為戰隊長，一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"전대장으로 그 아이가 선택되었다면, 다 그럴만한 이유가 있을 거고.","JPN":"あの子が戦隊長に選ばれたら、それなりの理由があるはずだし。","ENG":"And if she is chosen as our next Commander, I'm sure there's good reason for that too.","TWN":"如果那個孩子被選為戰隊長，也一定是有充分理由的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리니까 우선 그 아이를 만나보자.","JPN":"だから、まずはあの子に会ってみよう。","ENG":"So first, let's go meet her.","TWN":"所以，我們先去見見那個孩子吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"결정은…… 길고양이가 새로운 집을 찾은 뒤에 해도 늦지 않으니까.","JPN":"野良猫が新しい家を探した後に決めても……遅くないから。","ENG":"It won't be too late... to decide after we bring a stray cat to her new home.","TWN":"至於決定……等流浪的小貓找到新家之後再做也不遲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"길고양이가 새로운 집을 찾은 뒤라…….","JPN":"野良猫が新しい家を探した後、ね……","ENG":"After we bring a stray cat to her new home...","TWN":"找到新家啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"부전대장님!","JPN":"副戦隊長！","ENG":"Deputy Commander!","TWN":"副戰隊長！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L26_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"신참이…… 신참 녀석이 눈을 떴습니다요!","JPN":"新入りが……やつが目覚めたでやんす！","ENG":"The rookie...! She's awake!","TWN":"新人……新人醒過來了！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"일어났구나? 사고뭉치?","JPN":"起きたの？　トラブルメーカーさん。","ENG":"Rise and shine, troublemaker?","TWN":"你醒了？闖禍精？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"소방관이라서 그런가? 평소에 무모하다는 소리 자주 듣지 않아?","JPN":"消防士だからかな？　無謀だってよく言われない？","ENG":"Is it because you're a firefighter? Haven't you been called reckless before?","TWN":"因為仗著自己是消防員嗎？你以前是不是也經常聽到別人說你行事魯莽？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래서 어디 아픈 데는 없어?","JPN":"どこか痛むところはない？","ENG":"So? Does it hurt anywhere?","TWN":"怎麼樣？你有沒有哪裡不舒服？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……괜찮은 것 같아.","JPN":"……大丈夫みたいだ。","ENG":"...I think I'm all right.","TWN":"……好像沒事了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"설마, CRF도 제대로 다룰 줄 모르는 신참 카운터가 3종 침식체한테 달려들 줄이야.","JPN":"CRFもまともに扱えない新入りカウンターが第3種侵食体に立ち向かうとはね。","ENG":"Who knew a rookie Counter who doesn't even know how to use CRF properly could fight a Category 3 C.O. on her own.","TWN":"誰能想到，一個連CRF都不知道怎麼操控的新人，竟然會去招惹3類侵蝕體。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래도 첫 작전에 3종을 상대로 비등하게 싸웠으니 나름 소질은 있네.","JPN":"でも、初作戦で3種相手に互角に戦えたんだし、素質はあるみたいね。","ENG":"But seeing how you went neck-and-neck with a Category 3 on your first mission, I think you have potential.","TWN":"不過，你在第一次作戰中就能與3類侵蝕體打得不相上下，還是很有天賦的嘛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"헹! 너무 기를 세워주시는 거 아닙니까요?","JPN":"ふん！　おだてすぎじゃないでやんすか？","ENG":"Hmph! Don't you think you're inflating her ego a little too much?","TWN":"哼！你也太抬舉她了吧？副戰隊長！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"3종 같은 허접 침식체…… 시간과 예산만 주시면 저도 충분히 쓰러트릴 수 있습니다요!","JPN":"3種ごときのポンコツ侵食体……時間と予算さえいただければ、あたいだって十分倒せるでやんす！","ENG":"A lousy Category 3 C.O.... I could take one on if I was given enough time and resources too!","TWN":"區區3類侵蝕體……只要給我時間和預算，我也能輕鬆打倒喔！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 지금 질투하는 거야, 쥐스틴?","JPN":"ふふ、焼きもち焼いてるの、ジュスティーヌ？","ENG":"Fu fuu, are you being jealous right now, Justine Maisy?","TWN":"呵呵，你是在嫉妒嗎，潔絲婷？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"지, 질투가 아닙니다요!","JPN":"や、焼きもちなんかじゃないでやんす！","ENG":"J-jealous?! N-no!","TWN":"我、我才沒有呢！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"팩트입니다요! 논픽션입니다요! 리얼 버라이어티입니다요!","JPN":"事実でやんす！　ノンフィクションでやんす！　リアルバラエティーでやんす！","ENG":"It's a fact! Non-fiction! Reality TV!","TWN":"我說的是事實！是寫實文學！是即時觀察！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"한 가지만 물어봐도 돼?","JPN":"一つだけ、聞いていいか？","ENG":"Can I ask you a question?","TWN":"我可以問你一件事嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"으음? 뭐가 궁금한데?","JPN":"うん？　何？","ENG":"Mm? What do you want to know?","TWN":"嗯？你想問什麼？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국은 침식 재난을 미리 예측할 수 있는 거지?","JPN":"管理局は、侵食災難をある程度予測できるんだな。","ENG":"The Administration is able to predict Corruption disasters, right?","TWN":"管理局是不是能提前預測侵蝕災難？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ええ。","ENG":"...Yes.","TWN":"……沒錯。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"변수가 없지는 않지만, 어느 정도는 예측할 수 있어.","JPN":"変数がない訳ではないけど、ある程度は予測できる。","ENG":"Although there are many variables at play, they can make a rough prediction.","TWN":"雖然不能保證百分之百，但多多少少還是能預測到的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그럼, 그 화재에서는 왜 늦게 온 거야?","JPN":"……じゃあ、あの火災現場にはなぜ遅れて来たんだ？","ENG":"...Then, why were you late to the fire that time?","TWN":"……那麼，那場火災你們為什麼不早點來？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국이 조금만 더 서둘렀으면, 거기 있는 모두를 구할 수 있었던 거 아니야?","JPN":"管理局がもう少し急いでいれば、あそこにいた皆を助けられたんじゃないのか？","ENG":"If the Administration was a little quicker, then couldn't they have saved everyone there?","TWN":"如果管理局動作再快一點，不就可以救下所有人了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대장님, 동료들 그리고 그 아이도……!","JPN":"隊長も、仲間たちも、あの子どもも……！","ENG":"Captain, my colleagues, and even that kid...!","TWN":"隊長、同伴們，還有那個孩子……！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대답해, 내 말이 틀려!?","JPN":"答えてくれ、違うのか！？","ENG":"Answer me. Am I wrong?!","TWN":"回答我，我說錯了嗎？！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"무슨 헛소리를 하는 겁니까요! 그날 침식 현상은……!","JPN":"何バカなこと言ってるでやんすか！　あの日の侵食現象は……！","ENG":"That's nonsense! The Counterside Effect that day was–!","TWN":"你在說什麼呀！那天的侵蝕現象明明是……！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"쥐스틴!","JPN":"ジュスティーヌ！","ENG":"Justine!","TWN":"潔絲婷！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"부, 부전대장님?","JPN":"ふ、副戦隊長？","ENG":"D-Deputy Commander?","TWN":"副、副戰隊長？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……미안. 목이 좀 마르네. 당근 주스를 가져와 줄래?","JPN":"……ごめんなさい。ちょっと喉が渇いた。ニンジンジュースを持ってきてくれる？","ENG":"...I'm sorry. I'm a little thirsty. Could you get me some carrot juice?","TWN":"……抱歉。我有點口渴，能給我倒點紅蘿蔔汁嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"아, 알겠습니다요!","JPN":"わ、わかりましたでやんす！","ENG":"O-okay!","TWN":"啊，知道了啦！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RAT_YAKSHA_NULL_NULL","text":{"KOREA":"시원한 걸로 가져다드리겠습니다요!","JPN":"冷たいものを用意してくるでやんす！","ENG":"I'll get you an ice-cold one!","TWN":"我給你拿冰冰涼涼的來！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 일은 유감스럽게 됐어.","JPN":"あの事件は、お気の毒だと思ってるよ。","ENG":"I'm sorry for what happened that day.","TWN":"那件事我很遺憾。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그래, 네 말대로 관리국이 조금 더 빨리 개입했다면, 결과가 달라졌을지도 모르지.","JPN":"あなたの言う通り、管理局がもう少し早く動いていれば、違う結果になっていたかもしれない。","ENG":"Yes, if the Administration was a little faster, the outcome might have been different.","TWN":"你說的沒錯，如果管理局早點干預，結果可能會有所不同。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 관리국은 세계의 인과를 관리하는 기관이야.","JPN":"でも管理局は世界の因果を管理する機関よ。","ENG":"But the Administration is an organization that manages the causality of this world.","TWN":"但是，管理局這個組織所管理的是世界的因果。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"침식 현상이 외부에 노출되면 노출될수록, 세계 침식률을 가속시키는 결과를 불러올 테니까.","JPN":"侵食現象が外部に露出されるほど、世界の侵食は加速するの。","ENG":"The more the Counterside Effect is exposed to the outside, the more it will result in accelerating the world's Corruption rate.","TWN":"侵蝕現象暴露在外界越多，就越會加快世界侵蝕率的上升。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"납득하기 어려울 수도 있지만……. 그 상황에서는 널 구하는 게 최선이었어.","JPN":"あなたは納得できないかもしれないけど……あの状況では、あなた一人を助けるのが「最善」だった。","ENG":"I know it's difficult for you to understand, but... saving you was the best we could do in that situation.","TWN":"你可能很難理解，但……當時那種情況，救你才是最好的選擇。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"최선……!?","JPN":"最善だと！？","ENG":"The best you could do...?!","TWN":"最好的……？！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"구할 수 있었으면서도, 위험에 빠진 구조자를 구하지 않았으면서! 최선이었다고?","JPN":"助けられたはずなのに、危険に陥った救助者を見捨てておいてか！？","ENG":"You could've saved everyone, but you chose not to save those in danger! How can you call that doing your best?","TWN":"既然可以救人，卻對陷入危險的求救者視而不見！你告訴我這是最好的……？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내 탓을 하려면 얼마든지 해도 좋아.","JPN":"私を恨みたいなら、いくらでも恨んでいいよ。","ENG":"You can blame me all you want.","TWN":"你想怎麼責怪我都可以。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하지만 그런다고 달라지는 건 없을 거야.","JPN":"でも、私を恨んだところで何も変わらない。","ENG":"But it won't change what has already happened.","TWN":"但這不會改變任何事情。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 믿든, 믿지 않든…… 그게 이 세계의 진실이니까.","JPN":"あなたが信じようが信じまいが……それがこの世界の真実なのだから。","ENG":"Whether you believe it or not... it's still the truth of this world.","TWN":"不管你信不信……這就是這個世界的真相。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"웃기지 마, 내가 믿는 진실은 하나뿐이야.","JPN":"ふざけるな、アタシにとっての真実はただ一つだけだ。","ENG":"Shut it. There's only one truth that I believe.","TWN":"開什麼玩笑，我只相信一個真理。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"훌륭한 소방관이라면…… 어떤 상황에서도 포기하지 않는 다는 것.","JPN":"立派な消防士は……どんな状況でも諦めない。","ENG":"Excellent firefighters... never give up in any situation.","TWN":"一名優秀的消防員……在任何情況下都不會放棄。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"현장에서 구조자의 목숨도, 스스로의 목숨도 구해낼 수 있어야 한다고. 그렇게 배웠어.","JPN":"現場では救助者の命も、自分の命も守るものだと。アタシはそう教えてもらった。","ENG":"They should be able to save the lives of rescuees and themselves. That's what I was taught.","TWN":"在現場，無論是求救者的生命，還是自己的生命，我們都必須盡力拯救。這就是我學到的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"……오만한 생각이야.","JPN":"……傲慢な考え方ね。","ENG":"...You're being arrogant.","TWN":"……真是個傲慢的想法。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국조차 모두를 구할 수는 없어. 언젠가 반드시 선택의 때가 오게 될 거야.","JPN":"管理局すら万人を救うことはできないの。いつか必ず、どちらかを選ばないといけない瞬間が訪れる。","ENG":"Not even the Administration could save them all. And there will come a time when you have to make a choice.","TWN":"即使是管理局也無法拯救所有人。總有一天，你一定會遇到必須做出選擇的時刻。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그걸 감당할 수 있겠어?","JPN":"あなたはそれに耐えられるの？","ENG":"Are you sure you can handle that?","TWN":"那時，你還能這麼說嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"감당할 수 있겠냐고?","JPN":"耐えられるのかって？","ENG":"Can I handle it?","TWN":"……我還能這麼說嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그런 건 여기 오기 전부터 줄곧 감당해왔어.","JPN":"そんなもん、ここに来る前からずっと耐えてきた。","ENG":"I've been handling it long before I came here.","TWN":"可我在來到這裡之前，一直是這麼做的。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"부탁이 있어.","JPN":"頼みがある。","ENG":"I have something to ask.","TWN":"我有個請求。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국의 야크샤 전대는 환상종 카운터로 구성된 전대라고 했지?","JPN":"管理局のヤクシャー戦隊は、幻想種のカウンターで構成された戦隊って言ってたよな。","ENG":"You said that the Administration's Yaksha Division consists of Bygone Counters, right?","TWN":"你說管理局的夜叉戰隊是由夢幻品種制裁者組成的戰隊吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그럼, 나를 전대원으로 받아줘.","JPN":"じゃあ、アタシを隊員として受け入れてくれ。","ENG":"Then accept me as a member.","TWN":"那麼，請接受我成為戰隊的一員。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"관리국을 싫어하는 거 아니었어?","JPN":"管理局が嫌いなんじゃなかったの？","ENG":"I thought you hated the Administration.","TWN":"你不討厭管理局嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"싫어해.","JPN":"嫌いだ。","ENG":"I do.","TWN":"不，我很討厭。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"인과가 어쩌고, 세계가 어쩌고……. 그딴 거창하고, 허무맹랑한 이야기 나는 관심 없으니까.","JPN":"因果がどうとか、世界がどうとか……そんな大それた話なんかには興味ない。","ENG":"But I'm not interested in such grandiose and absurd ideas about causality, the world, and so on.","TWN":"但是因果也好，世界也好……我對這些無稽之談不感興趣。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 이 힘으로 사람을 구하고, 한 가지 잊고 있었던 걸 깨달을 수 있었어.","JPN":"でも、アタシはこの力で人を助けることができた。そして一つ、忘れていたことを思い出したんだ。","ENG":"But after using this power to save someone, I realized something I had forgotten.","TWN":"不過在透過這種力量拯救了一個人的同時，我也意識到了自己曾經忽略的一件事。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나는 아직 소방관이고, 이 방화복이 내 각오였다는 걸.","JPN":"アタシはまだ消防士で、この防火服はアタシの覚悟ってことをな。","ENG":"I'm still a firefighter, and this fire suit is my determination.","TWN":"我仍然是一名消防員，這件消防服就是我的決心。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"화재 현장에서 구조자를 구하는데 수단이나 방법 같은 건 가리지 않아.","JPN":"火災現場で人を助ける時は手段を選ばない。","ENG":"I don't mind using any means necessary to rescue people in a fire.","TWN":"我會不惜一切手段和代價，拯救火災現場的求救者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"관리국의 정보와 힘이 있다면…… 지금까지는 구할 수 없었던 사람도 구할 수 있겠지.","JPN":"管理局の情報と力をもってすれば……今までは救えなかった人も救えるだろう。","ENG":"And if I have the Administration's intel and power... I'll be able to save others whom I couldn't save before.","TWN":"如果能借助管理局的資訊和力量……我們一定能夠拯救更多迄今為止無法拯救的人。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니까 나를 전대원으로 받아줘, 주디 스위프트.","JPN":"だからアタシを戦隊に受け入れてくれ、ジュディ・スウィフト。","ENG":"So, I want you to accept me into your division, Judy Swift.","TWN":"所以，請接受我成為戰隊的一員，茱蒂·斯威福特。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시는 아무도 내 앞에서 죽게 내버려두지 않겠어.","JPN":"もう二度と、目の間で誰かを死なせたりしない。","ENG":"I will not allow anyone to die on my watch anymore.","TWN":"我不會再讓任何人死在我面前。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그게…… 타오르는 불속에서 홀로 살아남아버린 내가 짊어질 유일한 의무니까.","JPN":"それが……あの炎の中から一人生き残ってしまったアタシが背負うべき、唯一の義務だから。","ENG":"Because... that's the one duty that I must bear as the sole survivor of that fire.","TWN":"那是……我必須承擔的唯一義務，因為我是大火中唯一的倖存者。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};